// src/pages/Products.js
import { useEffect, useState } from "react";
import {
  collection,
  getDocs,
  addDoc,
  deleteDoc,
  doc,
  updateDoc,
  query,
  where,
} from "firebase/firestore";
import { db } from "../firebase/config";
import { useParams, useNavigate } from "react-router-dom";
import Modal from "../components/Modal";

const EMPTY_FORM = { name: "", desc: "", price: "", cal: "", img: "" };

const Products = () => {
  const { category } = useParams();
  const navigate = useNavigate();

  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [form, setForm] = useState(EMPTY_FORM);
  const [saving, setSaving] = useState(false);

  const activeCategory = category || null;

  const fetchProducts = async () => {
    setLoading(true);
    try {
      let q;
      if (activeCategory) {
        q = query(
          collection(db, "products"),
          where("category", "==", activeCategory)
        );
      } else {
        q = collection(db, "products");
      }
      const snap = await getDocs(q);
      setProducts(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    const snap = await getDocs(collection(db, "categories"));
    setCategories(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
  };

  useEffect(() => {
    fetchProducts();
    fetchCategories();
  }, [activeCategory]);

  const openAdd = () => {
    setEditTarget(null);
    setForm({ ...EMPTY_FORM, category: activeCategory || "" });
    setModalOpen(true);
  };

  const openEdit = (prod) => {
    setEditTarget(prod);
    setForm({
      name: prod.name,
      desc: prod.desc,
      price: prod.price,
      cal: prod.cal,
      img: prod.img,
      category: prod.category,
    });
    setModalOpen(true);
  };

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    const data = {
      name: form.name,
      desc: form.desc,
      price: Number(form.price),
      cal: Number(form.cal),
      img: form.img,
      category: form.category,
    };
    try {
      if (editTarget) {
        await updateDoc(doc(db, "products", editTarget.id), data);
        setProducts((prev) =>
          prev.map((p) => (p.id === editTarget.id ? { ...p, ...data } : p))
        );
      } else {
        const ref = await addDoc(collection(db, "products"), data);
        if (!activeCategory || data.category === activeCategory) {
          setProducts((prev) => [...prev, { id: ref.id, ...data }]);
        }
      }
      setModalOpen(false);
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("هل تريد حذف هذا المنتج؟")) return;
    await deleteDoc(doc(db, "products", id));
    setProducts((prev) => prev.filter((p) => p.id !== id));
  };

  const title = activeCategory
    ? `منتجات: ${activeCategory}`
    : "جميع المنتجات";

  return (
    <div className="page">
      <div className="page-header">
        <div>
          {activeCategory && (
            <button
              className="back-btn"
              onClick={() => navigate("/dashboard/categories")}
            >
              ← الأصناف
            </button>
          )}
          <h1 className="page-title">{title}</h1>
          <p className="page-desc">
            {products.length} منتج
            {activeCategory ? ` في صنف ${activeCategory}` : ""}
          </p>
        </div>
        <button className="btn-primary" onClick={openAdd}>
          + إضافة منتج
        </button>
      </div>

      {/* Category filter tabs */}
      {!activeCategory && categories.length > 0 && (
        <div className="cat-tabs">
          <button
            className="cat-tab active"
            onClick={() => navigate("/dashboard/products")}
          >
            الكل
          </button>
          {categories.map((c) => (
            <button
              key={c.id}
              className="cat-tab"
              onClick={() => navigate(`/dashboard/products/${c.name}`)}
            >
              {c.name}
            </button>
          ))}
        </div>
      )}

      {loading ? (
        <div className="loading-state">
          <div className="loader" />
        </div>
      ) : products.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">◉</div>
          <p>لا توجد منتجات بعد</p>
          <button className="btn-primary" onClick={openAdd}>
            أضف أول منتج
          </button>
        </div>
      ) : (
        <div className="grid grid-3">
          {products.map((prod) => (
            <div key={prod.id} className="prod-card">
              <div className="prod-img-wrap">
                {prod.img ? (
                  <img
                    src={prod.img}
                    alt={prod.name}
                    className="prod-img"
                    onError={(e) => {
                      e.target.style.display = "none";
                      e.target.nextSibling.style.display = "flex";
                    }}
                  />
                ) : null}
                <div
                  className="prod-img-fallback"
                  style={{ display: prod.img ? "none" : "flex" }}
                >
                  ◉
                </div>
                <div className="prod-category-badge">{prod.category}</div>
              </div>
              <div className="prod-body">
                <h3 className="prod-name">{prod.name}</h3>
                <p className="prod-desc">{prod.desc}</p>
                <div className="prod-meta">
                  <span className="prod-price">{prod.price} ر.س</span>
                  <span className="prod-cal">{prod.cal} سعرة</span>
                </div>
                <div className="prod-actions">
                  <button
                    className="btn-sm edit"
                    onClick={() => openEdit(prod)}
                  >
                    ✎ تعديل
                  </button>
                  <button
                    className="btn-sm del"
                    onClick={() => handleDelete(prod.id)}
                  >
                    ✕ حذف
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      <Modal
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        title={editTarget ? "تعديل المنتج" : "إضافة منتج جديد"}
      >
        <form onSubmit={handleSave}>
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">اسم المنتج</label>
              <input
                className="form-input"
                placeholder="مثال: برغر كلاسيك"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                required
              />
            </div>
            <div className="form-group">
              <label className="form-label">الصنف</label>
              <select
                className="form-input"
                value={form.category}
                onChange={(e) =>
                  setForm({ ...form, category: e.target.value })
                }
                required
              >
                <option value="">اختر صنفًا</option>
                {categories.map((c) => (
                  <option key={c.id} value={c.name}>
                    {c.name}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">الوصف</label>
            <textarea
              className="form-input form-textarea"
              placeholder="وصف المنتج..."
              value={form.desc}
              onChange={(e) => setForm({ ...form, desc: e.target.value })}
              rows={3}
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label className="form-label">السعر (ر.س)</label>
              <input
                type="number"
                className="form-input"
                placeholder="0"
                value={form.price}
                onChange={(e) => setForm({ ...form, price: e.target.value })}
                required
                min="0"
                step="0.01"
                dir="ltr"
              />
            </div>
            <div className="form-group">
              <label className="form-label">السعرات الحرارية</label>
              <input
                type="number"
                className="form-input"
                placeholder="0"
                value={form.cal}
                onChange={(e) => setForm({ ...form, cal: e.target.value })}
                min="0"
                dir="ltr"
              />
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">رابط الصورة</label>
            <input
              className="form-input"
              placeholder="https://..."
              value={form.img}
              onChange={(e) => setForm({ ...form, img: e.target.value })}
              dir="ltr"
            />
          </div>

          <div className="modal-actions">
            <button
              type="button"
              className="btn-ghost"
              onClick={() => setModalOpen(false)}
            >
              إلغاء
            </button>
            <button
              type="submit"
              className="btn-primary"
              disabled={saving}
            >
              {saving ? <span className="btn-loader" /> : "حفظ المنتج"}
            </button>
          </div>
        </form>
      </Modal>
    </div>
  );
};

export default Products;
